#include "surface_ops.h"
__declspec(dllexport) void run(void) { H radius,rect,color; cvm_pop(radius); cvm_pop(color); cvm_pop(rect); HWND w=surface_hwnd(); if(w){RECT r; surface_rect_from_h(rect,&r); int rr=(int)cvm_h_to_u64(radius); HDC dc=GetDC(w); HBRUSH br=CreateSolidBrush((COLORREF)cvm_h_to_u64(color)); HPEN pen=CreatePen(PS_NULL,0,(COLORREF)0); HGDIOBJ old_br=SelectObject(dc,br); HGDIOBJ old_pen=SelectObject(dc,pen); RoundRect(dc,r.left,r.top,r.right,r.bottom,rr,rr); SelectObject(dc,old_pen); SelectObject(dc,old_br); DeleteObject(pen); DeleteObject(br); ReleaseDC(w,dc);} cnext(); }
